import type { Ref } from 'vue';
import { detectApiProvider, filterApiParams, normalizeApiEndpoint } from '../../settings';
import { callAIWithTavernSupport } from '../../utils/api';

export type StreamingExecutor = (requestPayload: Record<string, any>, progressRef: Ref<number>) => Promise<string>;

export interface ToolsAiSettings {
  use_tavern_api?: boolean;
  api_endpoint: string;
  api_key: string;
  [key: string]: any;
}

export interface RequestToolsAiTextOptions {
  requestPayload: Record<string, any>;
  settings: ToolsAiSettings;
  progressRef?: Ref<number>;
  streamExecutor?: StreamingExecutor;
}


export function extractJsonFromText(text: string): { json: any; rawText: string } | null {
  const trimmedText = text.trim();

  // Method 1: parse directly if text itself is JSON
  try {
    const parsed = JSON.parse(trimmedText);
    if (typeof parsed === 'object' && parsed !== null) {
      return { json: parsed, rawText: trimmedText };
    }
  } catch {
    // try next strategy
  }

  // Method 2: parse JSON from fenced code block
  const codeBlockMatch = trimmedText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (codeBlockMatch) {
    try {
      const parsed = JSON.parse(codeBlockMatch[1].trim());
      if (typeof parsed === 'object' && parsed !== null) {
        return { json: parsed, rawText: codeBlockMatch[1].trim() };
      }
    } catch {
      // try next strategy
    }
  }

  // Method 3: extract first balanced JSON object
  const braceStart = trimmedText.indexOf('{');
  if (braceStart !== -1) {
    let braceCount = 0;
    let braceEnd = -1;

    for (let i = braceStart; i < trimmedText.length; i++) {
      if (trimmedText[i] === '{') braceCount++;
      if (trimmedText[i] === '}') braceCount--;
      if (braceCount === 0) {
        braceEnd = i;
        break;
      }
    }

    if (braceEnd !== -1) {
      const jsonCandidate = trimmedText.substring(braceStart, braceEnd + 1);
      try {
        const parsed = JSON.parse(jsonCandidate);
        if (typeof parsed === 'object' && parsed !== null) {
          return { json: parsed, rawText: jsonCandidate };
        }
      } catch {
        // invalid JSON candidate
      }
    }
  }

  return null;
}
function extractStreamContent(chunk: any): string | null {
  // OpenAI format
  if (chunk.choices?.[0]?.delta?.content) {
    return chunk.choices[0].delta.content;
  }

  // Claude format
  if (chunk.delta?.text) {
    return chunk.delta.text;
  }

  // Generic fallback formats
  if (typeof chunk.content === 'string') {
    return chunk.content;
  }
  if (typeof chunk.text === 'string') {
    return chunk.text;
  }
  if (typeof chunk.response === 'string') {
    return chunk.response;
  }

  return null;
}

async function requestToolsAiTextWithStreaming(
  requestPayload: Record<string, any>,
  settings: ToolsAiSettings,
  progressRef: Ref<number>,
): Promise<string> {
  const apiUrl = normalizeApiEndpoint(settings.api_endpoint);
  const provider = detectApiProvider(settings.api_endpoint);
  const wantsStream = requestPayload.stream === true;

  // Keep payload provider-compatible
  const filteredPayload = filterApiParams(requestPayload, settings.api_endpoint);

  // Auto-fallback for unsupported providers
  if (!wantsStream || provider === 'gemini') {
    if (wantsStream && provider === 'gemini') {
      console.warn('⚠️ 当前 API 不支持流式输出，已自动切换为普通模式');
    }

    delete filteredPayload.stream;

    const response = await fetch(apiUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${settings.api_key}`,
      },
      body: JSON.stringify(filteredPayload),
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`API 请求失败 (${response.status}): ${errorText}`);
    }

    const data = await response.json();
    progressRef.value = 100;

    const finishReason = data.choices?.[0]?.finish_reason;
    if (finishReason === 'content_filter' || finishReason === 'PROHIBITED_CONTENT') {
      throw new Error(
        `内容被 AI 安全过滤器拦截 (finish_reason: ${finishReason})\n\n` +
          `输入内容可能包含敏感词汇，或请求的输出被认为不符合安全准则。\n` +
          `建议检查并修改输入内容，或尝试换一个模型。`,
      );
    }

    const content = data.choices?.[0]?.message?.content?.trim();
    if (!content) {
      console.warn('⚠️ API 返回数据缺少内容:', JSON.stringify(data).substring(0, 300));
      throw new Error('AI 返回了空内容，请检查 API 设置或重试');
    }

    return content;
  }

  filteredPayload.stream = true;

  const response = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${settings.api_key}`,
    },
    body: JSON.stringify(filteredPayload),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`流式请求失败：${response.status} ${response.statusText}\n${errorText.slice(0, 400)}`);
  }

  if (!response.body) {
    throw new Error('该 API 未返回可读流，请关闭流式模式或检查端点支持情况');
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder('utf-8');
  let buffer = '';
  let done = false;
  let result = '';

  progressRef.value = 0;

  const processLine = (line: string): boolean => {
    const trimmed = line.trim();
    if (!trimmed) {
      return false;
    }

    if (trimmed === 'data: [DONE]' || trimmed === '[DONE]') {
      return true;
    }

    const payloadText = trimmed.startsWith('data:') ? trimmed.slice(5).trim() : trimmed;
    if (!payloadText || payloadText === '[DONE]') {
      return false;
    }

    try {
      const payloadJson = JSON.parse(payloadText);
      const deltaText = extractStreamContent(payloadJson);
      if (deltaText) {
        result += deltaText;
        progressRef.value = Math.min(progressRef.value + 2, 98);
      }
    } catch (parseError) {
      console.warn('无法解析流式数据块:', payloadText.slice(0, 100), parseError);
    }

    return false;
  };

  while (!done) {
    const { value, done: readerDone } = await reader.read();

    if (value) {
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop() ?? '';

      for (const line of lines) {
        if (processLine(line)) {
          done = true;
          break;
        }
      }
    }

    if (readerDone) {
      done = true;
    }
  }

  if (buffer && !done) {
    processLine(buffer);
  }

  progressRef.value = 100;

  if (!result || result.trim() === '') {
    throw new Error('AI 返回了空内容，请检查 API 设置或重试');
  }

  return result;
}

export async function requestToolsAiText(options: RequestToolsAiTextOptions): Promise<string> {
  const { requestPayload, settings, progressRef, streamExecutor } = options;

  if (settings.use_tavern_api) {
    return callAIWithTavernSupport(requestPayload.messages, settings, {
      onProgress: progressRef ? p => (progressRef.value = p) : undefined,
    });
  }

  const wantsStreaming = requestPayload.stream === true;

  if (wantsStreaming && progressRef) {
    if (streamExecutor) {
      return streamExecutor(requestPayload, progressRef);
    }

    return requestToolsAiTextWithStreaming(requestPayload, settings, progressRef);
  }

  const apiUrl = normalizeApiEndpoint(settings.api_endpoint);
  const filteredPayload = filterApiParams(requestPayload, settings.api_endpoint);
  delete filteredPayload.stream;

  const response = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${settings.api_key}`,
    },
    body: JSON.stringify(filteredPayload),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`API 请求失败 (${response.status}): ${errorText}`);
  }

  const data = await response.json();
  const content = data?.choices?.[0]?.message?.content?.trim();

  if (!content) {
    throw new Error('AI 返回了空内容，请检查 API 设置或重试');
  }

  if (progressRef) {
    progressRef.value = 100;
  }

  return content;
}


/**
 * 流式请求并通过回调实时吐出「累计文本」。
 *
 * 与 requestToolsAiText 不同：这里把每次增量后的「完整累计文本」通过 onChunk 回调出去，
 * 方便 UI 边生成边显示（打字机效果）。
 * - 直连 API 且端点支持流式：真流式逐块回调。
 * - 酒馆 API / 不支持流式的端点：退化为一次性返回（结束时回调一次完整文本）。
 *
 * @returns 最终完整文本
 */
export async function streamToolsAiText(
  requestPayload: Record<string, any>,
  settings: ToolsAiSettings,
  onChunk: (fullText: string) => void,
): Promise<string> {
  // 酒馆 API：不支持增量回调，直接走普通通道，结束回调一次
  if (settings.use_tavern_api) {
    const text = await callAIWithTavernSupport(requestPayload.messages, settings, {});
    onChunk(text);
    return text;
  }

  const apiUrl = normalizeApiEndpoint(settings.api_endpoint);
  const provider = detectApiProvider(settings.api_endpoint);
  const filteredPayload = filterApiParams(requestPayload, settings.api_endpoint);

  // 不支持流式的端点（如部分 Gemini 兼容层）：退化为普通请求
  if (provider === 'gemini') {
    delete filteredPayload.stream;
    const response = await fetch(apiUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${settings.api_key}` },
      body: JSON.stringify(filteredPayload),
    });
    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`API 请求失败 (${response.status}): ${errorText}`);
    }
    const data = await response.json();
    const content = data?.choices?.[0]?.message?.content?.trim();
    if (!content) throw new Error('AI 返回了空内容，请检查 API 设置或重试');
    onChunk(content);
    return content;
  }

  filteredPayload.stream = true;
  const response = await fetch(apiUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${settings.api_key}` },
    body: JSON.stringify(filteredPayload),
  });
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`流式请求失败：${response.status} ${response.statusText}\n${errorText.slice(0, 400)}`);
  }
  if (!response.body) {
    // 没有可读流：退化处理
    const data = await response.json().catch(() => null);
    const content = data?.choices?.[0]?.message?.content?.trim() || '';
    if (!content) throw new Error('AI 返回了空内容，请检查 API 设置或重试');
    onChunk(content);
    return content;
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder('utf-8');
  let buffer = '';
  let result = '';
  let done = false;

  const processLine = (line: string): boolean => {
    const trimmed = line.trim();
    if (!trimmed) return false;
    if (trimmed === 'data: [DONE]' || trimmed === '[DONE]') return true;
    const payloadText = trimmed.startsWith('data:') ? trimmed.slice(5).trim() : trimmed;
    if (!payloadText || payloadText === '[DONE]') return false;
    try {
      const payloadJson = JSON.parse(payloadText);
      const deltaText = extractStreamContent(payloadJson);
      if (deltaText) {
        result += deltaText;
        onChunk(result);
      }
    } catch {
      /* 单块解析失败忽略 */
    }
    return false;
  };

  while (!done) {
    const { value, done: readerDone } = await reader.read();
    if (value) {
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop() ?? '';
      for (const line of lines) {
        if (processLine(line)) {
          done = true;
          break;
        }
      }
    }
    if (readerDone) done = true;
  }
  if (buffer && !done) processLine(buffer);

  if (!result || result.trim() === '') {
    throw new Error('AI 返回了空内容，请检查 API 设置或重试');
  }
  return result;
}
